import { AxiosError } from 'axios';
import { Service } from 'typedi';
import winston from 'winston';

import { Logger } from '@Decorators/Logger';

import { gameEngineService } from '@Libs/axios';
import { env } from '@Libs/env';

import { EmployeeType } from '@Enums/EmployeeType';
import { JwtTokenType } from '@Enums/JwtTokenType';

import { BasicError } from '@Errors/BasicError';
import { ErrorCode } from '@Errors/ErrorCode';

import { Employee } from '@Entities/Employee';

@Service()
export class GameService {
  constructor(@Logger(module) private readonly logger: winston.Logger) {}

  async generateLoginToken(identity: Employee, requestUsername?: string, eventCode?: string) {
    const sub = identity?.username || requestUsername;
    if (!sub) {
      throw new BasicError(ErrorCode.GAME_ENGINE_GENERATE_TOKEN_ERROR, 400);
    }
    const normalizedEventCode = (eventCode || '').trim() || 'TET2026';

    const roles = ['PLAYER'];
    const level = identity?.agency
      ? (identity.agency.id === env.migration.agencyId
        ? 'F1'
        : (identity.agency?.parentAgency?.id === env.migration.agencyId ? 'F2' : 'F3'))
      : undefined;
    if (level === 'F1' && identity?.type === EmployeeType.ADM) {
      roles.push('ADMIN');
    }

    const identityName = (
      identity?.username
      || sub
    ).trim();
    const agencyName = identity?.agency?.agencyName?.trim();
    const parentAgencyName = identity?.agency?.parentAgency?.agencyName?.trim();
    const name = level === 'F1'
      ? identityName
      : level === 'F2'
        ? [agencyName, identityName].filter(Boolean).join('/')
        : level === 'F3'
          ? [parentAgencyName, agencyName].filter(Boolean).join('/')
          : identityName;
    const agency = identity?.agency?.agencyCode;
    const parent = identity?.agency?.parentAgency?.agencyCode;

    if (!env.externalService.gameEngine.apiKey) {
      throw new BasicError(ErrorCode.GAME_ENGINE_GENERATE_TOKEN_ERROR, 500);
    }

    const apiKeyHeader = env.externalService.gameEngine.apiKeyHeader;
    const headers: Record<string, string> = {
      'content-type': 'application/json',
      [apiKeyHeader]: env.externalService.gameEngine.apiKey,
    };

    const payload = {
      sub,
      roles,
      tokenType: JwtTokenType.EXTERNAL_USER_JWT,
      issuer: 'airdata-ats',
      expiresIn: '7d',
      claims: {
        name,
        level,
        agency,
        parent,
      },
    };

    const response = await gameEngineService
      .post('/auth/generate', payload, { headers })
      .catch((error: AxiosError<any>) => {
        this.logger.warn('generateLoginToken:: calling game auth generate failed: ', error);
        throw new BasicError(error.response?.data?.message || error.message, error.response?.status);
      });

    const token = response?.data?.token;
    if (!token) {
      throw new BasicError(ErrorCode.GAME_ENGINE_GENERATE_TOKEN_ERROR, 500);
    }

    return {
      token,
      redirectUrl: this.buildRedirectUrl(token, normalizedEventCode),
      sub,
      name,
      roles,
    };
  }

  private buildRedirectUrl(token: string, eventCode: string): string {
    const gameWebsiteUrl = env.serviceUrl.gameWebsiteUrl.replace(/\/+$/, '');
    return `${gameWebsiteUrl}/${encodeURIComponent(eventCode.trim())}?token=${encodeURIComponent(token)}`;
  }
}

