const resErrorInterceptor = (error: AxiosError) => {
  const { config, response } = error;
  if (env.apmEnabled) {
    const apm = Container.get<apm.Agent>('apmAgent');
    const stats = apm.currentTraceIds;
    if (stats['trace.id'] && !isIgnoreUrl(config.url)) {
      const content = `API Call Error FROM ${env.serviceName}:
PATH: ${config.method.toUpperCase()} ${config.url}
RESPONSE STATUS: ${response?.status} BODY: ${JSON.stringify(response?.data || {})}
