      if (Number(response?.status) >= 500 && `${response?.status}` !== '501') {
        sendHttpErrorAlertMessage(content);
      } else if (Number(response?.status) < 500) {
        sendHttp4xxErrorAlertMessage(content);
      }
    }
  }
  return Promise.reject(error);
};
