import { AgentRequestService } from '@Services/AgentRequestService';

import { GetFlightScheduleRequest } from '@Rests/types/GetFlightScheduleRequest';
import { CreateExchangeRateRequest, UpdateExchangeRateRequest } from '@Rests/types/ExchangeRateRequest';

const CURRENCY_CONVERSION_CACHE_KEY = 'CURRENCY_CONVERSION_CACHE_KEY';

@Service()
export class UtilService implements ICurrencyConversionService {
  private referenceDataSearchHandlers: { [k: string]: Function } = {};
  constructor(
    @Logger(module) private readonly logger: winston.Logger,
    private readonly flightIntegrationService: FlightIntegrationService,
    private readonly airportRepo: AirportIATARepository,
    private readonly cacheRepo: CacheRepository,
    private readonly bookingService: BookingService,
    private readonly tourService: TourService,
    private readonly trainService: TrainTicketService,
    private readonly agentRequestService: AgentRequestService,
  ) {
    this.referenceDataSearchHandlers[ReferenceDataType.AIRPORT] =
      this.flightIntegrationService.referenceDataSearch.bind(this.flightIntegrationService);
    this.referenceDataSearchHandlers[ReferenceDataType.CARRIER] =
      this.flightIntegrationService.referenceDataSearch.bind(this.flightIntegrationService);
    this.referenceDataSearchHandlers[ReferenceDataType.CITY] =
      this.flightIntegrationService.referenceDataSearch.bind(this.flightIntegrationService);
    this.referenceDataSearchHandlers[ReferenceDataType.COUNTRY] =
      this.flightIntegrationService.referenceDataSearch.bind(this.flightIntegrationService);
    this.referenceDataSearchHandlers[ReferenceDataType.EQUIPMENT] =
      this.flightIntegrationService.referenceDataSearch.bind(this.flightIntegrationService);
  }

  async currencyConversion(params: CurrencyConversionRequest): Promise<CurrencyConversionResponse> {
    const key = CURRENCY_CONVERSION_CACHE_KEY;
    const dataCache = await this.cacheRepo.get(key);
    const currencyData: CurrencyConversionResponse = JSON.parse(dataCache || '{}');
    const convertVND = params.amount === 1 && params.from === 'USD' && params.to === 'VND';
    if (dataCache && currencyData?.convertedAmount && convertVND) {
      return {
        bankSellingRate: currencyData?.bankSellingRate,
        convertedAmount: currencyData?.bankSellingRate,
      };
    }
    const currency = await this.flightIntegrationService.currencyConversion(params);
    if (currency?.convertedAmount && convertVND) {
      await this.cacheRepo.setex(key, env.redis.currencyConvertExpirationTimeInSeconds, JSON.stringify(currency));
    }
    return currency;
  }

  async referenceDataSearch(params: ReferenceDataSearchRequest): Promise<ReferenceDataSearchResponse> {
    const handler = this.referenceDataSearchHandlers[params.type];
    if (!handler) throw new BusinessLogicError(ErrorCode.REFERENCE_DATA_TYPE_NOT_SUPPORTED);

    return handler(params);
  }

  async findCalendar(query: FlightCalendarInput, identity: Employee) {
    const { startDate, endDate } = query;
    const dateArr = getArrayDatesBetween(startDate, endDate).map((item) => ({
      date: item.date,
      flights: [],
      tours: [],
      trains: [],
    }));

    if (env.agencyConfig.title !== DEFAULT_AGENT_TITLE) {
      return dateArr;
    }
    const [bookingRes, tourRes, trainRes] = await Promise.all([
      this.bookingService.findFlightCalendar(query, identity),
      this.tourService.findFlightCalendar(query, identity),
      this.trainService.findFlightCalendar(query, identity),
    ]);

    const listBooking = bookingRes.map((booking) => ({
      ...booking,
      flightDates: booking.flightDates.map((date) => formatInTimezone(date)),
    }));

    const listTrain = trainRes.map((booking) => ({
      ...booking,
      departureDates: booking.departureDates.map((date) => formatInTimezone(date)),
    }));

    dateArr.forEach(dateResult => {
      const bookings = listBooking.filter((booking) => booking.flightDates.includes(dateResult.date));
      dateResult.flights = bookings;
      const tours = tourRes.filter((tour) => dateResult.date === moment(tour.startDate).format('YYYY-MM-DD'));
      dateResult.tours = tours;
      const trains = listTrain.filter((booking) => booking.departureDates.includes(dateResult.date));
      dateResult.trains = trains;
    });
    return dateArr;
  }

  async getFlightSchedules(params: GetFlightScheduleRequest) {
    return this.flightIntegrationService.getFlightSchedules(params);
  }

  async getFlightSchedulesConfig() {
    return this.flightIntegrationService.getFlightSchedulesConfig();
  }

  async getExchangeRate() {
    return this.flightIntegrationService.getExchangeRate();
  }

  async createExchangeRate(input: CreateExchangeRateRequest) {
    return this.flightIntegrationService.createExchangeRate(input);
  }

  async updateExchangeRate(id: string, input: UpdateExchangeRateRequest) {
    return this.flightIntegrationService.updateExchangeRate(id, input);
  }

  async translateFareRule(text: string) {
    return this.flightIntegrationService.translateFareRule(text);
  }
}

