  public async getToken() {
    const res = await vietNamAirlineService
      .get('/registrationweb/vi/account/enrollment', {
        params: {
          enrollSource: 'BGE',
        },
      })
      .catch((error: AxiosError) => {
        this.logger.warn('getToken:: calling getToken failed: ', error);
        throw new BasicError(error.response?.data?.message || error.message, error.response?.status);
      });
    let html = res.data.replace(/\r?\n|\r/g, '').toString();
    const index = html.indexOf('__RequestVerificationToken');
    // INDEX + 49
    html = html.slice(index + 49);
    const indexLast = html.indexOf('"');
    const token = html.slice(0, indexLast);
    const cookieInHeader = res.headers['set-cookie'];
    const uniqueStrings = [];
    for (const str of cookieInHeader) {
      if (!uniqueStrings.includes(str)) {
        uniqueStrings.push(str);
      }
    }
    const output = uniqueStrings.join('; ');
    const cookie = output.replace(/; path=\/; HttpOnly/g, '');
    return { token, cookie };
  }

  public async checkExists(req: CheckEmailAndPhoneInput) {
    const res = await vietNamAirlineService
      .get('/registrationweb/vi//account/checkemailandphone', {
        headers: {
          'content-type': 'application/json',
        },
        params: {
          email: req.email,
          phoneCountryCode: req.phoneCountryCode,
          phone: req.phone,
        },
      })
      .catch((error: AxiosError) => {
        this.logger.warn('checkExists:: calling checkExit failed: ', error);
        throw new BasicError(error.response?.data?.message || error.message, error.response?.status);
      });
    this.logger.info('checkExists:: response: ', res.status, res.data);
    if (res.data.Message.includes('Số điện thoại đã tồn tại')) {
      throw new ConflictError(ErrorCode.PHONE_NUMBER_ALREADY_IN_USE);
    }
    if (res.data.Message.includes('Địa chỉ email đã tồn tại')) {
      throw new ConflictError(ErrorCode.EMAIL_ADDRESS_ALREADY_IN_USE);
    }
    return res.data;
  }

  public async createMemberCard(req: CreateMemberCardInput, employee: Employee) {
    let contact;
    if (req.contactId) {
      contact = await this.contactService.findById(req.contactId);
      if (!contact) throw new NotFoundError(ErrorCode.CONTACT_NOT_FOUND);
    }
    const getToken = await this.getToken();
    const birthDay = new Date(req.birthDay);
    const data = {
