          Cookie: getToken.cookie,
        },
      })
      .catch((error: AxiosError) => {
        this.logger.warn('createMemberCard:: calling failed: ', error);
        throw new BasicError(error.response?.data?.message || error.message, error.response?.status);
      });
    this.logger.info('createMemberCard:: response: ', res.status, res.data);
    if (res.status === 200 && res.data.Message.includes('Tên và ngày sinh của Quý khách đã tồn tại')) {
      throw new ConflictError(ErrorCode.USERNAME_ALREADY_IN_USE);
    }
    if (res.status === 206 || res.data.Code === 'ERROR') {
      throw new ConflictError(ErrorCode.PHONE_NUMBER_OR_EMAIL_ALREADY_IN_USE);
    }
    const startIndex = res.data.Message.indexOf('<strong>') + '<strong>'.length;
    const endIndex = res.data.Message.indexOf('</strong>', startIndex);
    const membershipCardNumber = res.data.Message.slice(startIndex, endIndex);
    const createVnaMemberCardRes = {
      cardNumber: membershipCardNumber,
    };
    if (contact) {
      const ms = new MembershipCard();
      ms.fullName = `${contact.lastName} ${contact.firstName}`;
      ms.airlineCode = Airline.VIETNAM_AIRLINE;
      ms.contact = contact;
      ms.employee = employee;
      ms.cardNumber = membershipCardNumber;
      await this.membershipCardRepo.create(ms);
    }
    return createVnaMemberCardRes;
  }
